import numpy as np
from scipy import ndimage as ndi
from scipy.interpolate import NearestNDInterpolator
from scipy.spatial import cKDTree


def equalize_hist(array):
    max_val = np.iinfo(array.dtype).max
    unique, count = np.unique(array, return_counts=True)

    hist = np.zeros(max_val + 1)
    hist[unique] = count / len(array)

    new_array = np.zeros_like(array, array.dtype)
    for i in range(array.shape[0]):
        new_array[i] = int((max_val - 1) * hist[array[i]])
    return new_array


def fill_with_global_mean(original_img, non_black_indices, black_px_indices):
    filled = original_img.copy()
    mean = np.mean(original_img[non_black_indices], axis=0)
    filled[black_px_indices] = mean
    return filled


def fill_with_nearest(img, non_black_pixel_mask, black_pixel_mask):
    nearest_interpolator = NearestNDInterpolator(
        non_black_pixel_mask, img[non_black_pixel_mask].ravel()
    )
    pixels_without_value = np.where(black_pixel_mask == 255)
    result = img.copy()
    result[pixels_without_value] = nearest_interpolator(*pixels_without_value)
    return result


def fill_with_local_maximum(img, missing_pixel_mask, kernel_size):
    """Returns a copy of the image having its missing pixels filled with the local
    maximum within a radius of `kernel_size`"""
    img_blurred = ndi.maximum_filter(img, size=kernel_size, mode="nearest")
    return np.where(missing_pixel_mask, img_blurred, img)


def fill_with_weighted_neighbours_mean(
    img, non_black_pixel_mask, black_pixel_mask=None, num_neigh=10
):
    """Fills the holes in the image by giving to each black pixel (value == 0) the value
    of the weighted mean of the nearest non-black pixels.

    :param img: numpy.ndarray, the image to fill
    :param non_black_pixel_mask: numpy.ndarray, mask of the pixels that actually have a value
    :param black_pixel_mask: numpy.ndarray, mask of the pixels that you want the value tu be filled
    :param num_neigh: int, number of neighbours tu use to compute the pixel value
    :return: numpy.ndarray, the resulting image
    """
    black_pixel_mask = (
        np.invert(non_black_pixel_mask)
        if black_pixel_mask is None
        else black_pixel_mask
    )

    non_black_pixel = np.transpose(np.nonzero(non_black_pixel_mask))
    black_pixel_indices = np.transpose(np.nonzero(black_pixel_mask))
    tree = cKDTree(non_black_pixel)
    dists, closest = tree.query(black_pixel_indices, num_neigh)
    if num_neigh == 1:
        dists, closest = [[ds] for ds in dists], [[cs] for cs in closest]

    black_pixel_indices = map(tuple, black_pixel_indices)
    filled = img.copy()
    for pixel, neighbours, distances in zip(black_pixel_indices, closest, dists):
        neighbours_coords = (tuple(non_black_pixel[index]) for index in neighbours)
        sum_distances = sum(distances)
        filled[pixel] = sum(
            img[neighbour] * distance / sum_distances
            for neighbour, distance in zip(neighbours_coords, distances)
        )
    return filled


def calc_index(value, min_value, diff, step):
    return int(((value - min_value) / diff) * step)


def mask_hist(x, y, step, is_empty_val=lambda x: False):
    assert x.shape == y.shape
    x_min, x_max = np.nanmin(x), np.nanmax(x)
    x_diff = x_max - x_min
    hist = [[] for _ in range(step + 1)]

    index_func = lambda val: calc_index(val, x_min, x_diff, step)

    for x_value, y_value in zip(x.ravel(), y.ravel()):
        if not is_empty_val(x_value):
            hist[index_func(x_value)].append(y_value)

    return [np.mean(v, axis=0) if v else np.zeros_like(y[0]) for v in hist], index_func
